class SimpleCache {
  constructor(prefix = 'cache_') {
    this.prefix = prefix;
  }

  /**
   * Save data to cache with an expiration time.
   * @param {string} key - The cache key (e.g., city name)
   * @param {any} data - The data to store
   * @param {number} ttlInMinutes - Time-to-live in minutes
   */
  set(key, data, ttlInMinutes = 10) {
    const item = {
      data: data,
      expiry: Date.now() + (ttlInMinutes * 60 * 1000)
    };
    try {
      localStorage.setItem(this.prefix + key, JSON.stringify(item));
    } catch (error) {
      console.error('Failed to set cache:', error);
    }
