  /**
   * Get data from cache. Returns null if expired or not found.
   * @param {string} key - The cache key
   * @returns {any|null}
   */
  get(key) {
    const cachedItem = localStorage.getItem(this.prefix + key);
    if (!cachedItem) return null;

