### 1. Basic In‑Memory Cache with TTL

Place this in a file like `cache.js`:

```javascript
class SimpleCache {
  constructor(defaultTTL = 5 * 60 * 1000) { // TTL in milliseconds (default 5 minutes)
    this.store = new Map();
    this.ttl = defaultTTL;
  }

  // Store a value with an optional custom TTL (in ms)
  set(key, value, ttl = this.ttl) {
    const expiresAt = Date.now() + ttl;
    this.store.set(key, { value, expiresAt });
    this.cleanup(); // Remove any other expired entries
  }

  // Retrieve a value; returns null if missing or expired
  get(key) {
    const entry = this.store.get(key);
    if (!entry) return null;
    if (Date.now() > entry.expiresAt) {
      this.store.delete(key);
      return null;
    }
    return entry.value;
  }

  // Check if a key exists and is still valid
  has(key) {
    const entry = this.store.get(key);
    if (!entry) return false;
    if (Date.now() > entry.expiresAt) {
      this.store.delete(key);
      return false;
    }
    return true;
  }

  // Remove a specific key
  delete(key) {
    this.store.delete(key);
  }

  // Clear every entry
  clear() {
    this.store.clear();
  }

  // Remove all expired entries (optional – called automatically on set)
  cleanup() {
    const now = Date.now();
    for (const [key, entry] of this.store) {
      if (now > entry.expiresAt) {
        this.store.delete(key);
      }
    }
  }
}

// Export a singleton instance if desired
const apiCache = new SimpleCache(5 * 60 * 1000); // 5 minutes
export default apiCache;
```

